<?php
namespace App\Domain\Equipment;use InvalidArgumentException;
final class CharacterEquipmentSlot{const MAIN_HAND='main_hand';const OFF_HAND='off_hand';const HISTORICAL_WEAPON_MAIN='weapon_main';const HELMET='helmet';const ARMOR='armor';const GLOVES='gloves';const BOOTS='boots';const NECKLACE='necklace';const RING_LEFT='ring_left';const RING_RIGHT='ring_right';private const DEFINITIONS=[self::MAIN_HAND=>['Mano principal',EquipmentType::WEAPON],self::OFF_HAND=>['Mano secundaria',EquipmentType::WEAPON],self::HELMET=>['Casco',EquipmentType::HELMET],self::ARMOR=>['Armadura',EquipmentType::ARMOR],self::GLOVES=>['Guantes',EquipmentType::GLOVES],self::BOOTS=>['Botas',EquipmentType::BOOTS],self::NECKLACE=>['Collar',EquipmentType::NECKLACE],self::RING_LEFT=>['Anillo izquierdo',EquipmentType::RING],self::RING_RIGHT=>['Anillo derecho',EquipmentType::RING]];public static function all(){return array_keys(self::DEFINITIONS);}public static function label($slot){$slot=self::normalizeHistorical($slot);self::assertValid($slot);return self::DEFINITIONS[$slot][0];}public static function equipmentType($slot){$slot=self::normalizeHistorical($slot);self::assertValid($slot);return self::DEFINITIONS[$slot][1];}public static function slotsForType($type){EquipmentType::assertValid($type);return array_values(array_filter(self::all(),function($slot)use($type){return self::equipmentType($slot)===$type;}));}public static function normalizeHistorical($slot){return$slot===self::HISTORICAL_WEAPON_MAIN?self::MAIN_HAND:$slot;}public static function assertValid($slot){if(!is_string($slot)||!isset(self::DEFINITIONS[$slot]))throw new InvalidArgumentException('Invalid equipment slot.');return$slot;}private function __construct(){}}
